const guidesData = [
// ── יסודות ───────────────────────────────────────────────────────
{id:"bas-1",category:"basics",title:"איך מדליקים ומכבים את הטלפון?",steps:["הדלקה: לחצו לחיצה ארוכה (3-5 שניות) על כפתור ההפעלה שבצד הטלפון עד שהמסך יידלק.","כיבוי אנדרואיד: לחצו לחיצה ארוכה על כפתור ההפעלה > בחרו כיבוי > אשרו.","כיבוי אייפון (עם כפתור בית): לחצו לחיצה ארוכה על כפתור ההפעלה > גררו את המחוון ימינה לכיבוי.","כיבוי אייפון (ללא כפתור בית): לחצו בו-זמנית על כפתור ההפעלה ועל כפתור הווליום > גררו את המחוון לכיבוי."]},
{id:"bas-2",category:"basics",title:"איך טוענים את הסוללה?",steps:["חברו את כבל הטעינה לשקע החשמל ולמחבר בתחתית הטלפון.","מסך הטלפון יציג סמל של סוללה עם ברק – זה אומר שהטעינה פועלת.","טענו עד 80–100% לפני שמנתקים. עדיף לטעון לפני שהסוללה מרוקנת לגמרי.","אם הטלפון כבוי לגמרי – המתינו כמה דקות לאחר החיבור עד שיידלק מחדש."]},
{id:"bas-3",category:"basics",title:"איך מבצעים שיחת טלפון רגילה?",steps:["פתחו את אפליקציית הטלפון (סמל שפופרת ירוקה או כחולה).","לחצו על סמל לוח החיוג (ריבוע עם נקודות) כדי לפתוח את המקלדת המספרית.","הקלידו את מספר הטלפון המלא כולל קידומת (050, 052 וכו').","לחצו על כפתור החיוג הירוק להתחלת השיחה, ועל הכפתור האדום לסיום."]},
{id:"bas-4",category:"basics",title:"איך עונים לשיחה נכנסת?",steps:["כאשר הטלפון מצלצל, יופיע על המסך שם המתקשר (אם הוא שמור) או מספר הטלפון.","אם המסך נעול: גררו את האצבע על סמל הטלפון הירוק ימינה כדי לענות.","אם המסך פתוח: לחצו על הכפתור הירוק לעניה, או על האדום לדחיית השיחה.","לסיום השיחה: לחצו על הכפתור האדום."]},
{id:"bas-5",category:"basics",title:"איך נועלים ופותחים את המסך?",steps:["נעילה: לחצו לחיצה קצרה על כפתור ההפעלה שבצד הטלפון – המסך יכבה ויינעל.","פתיחה: לחצו שוב לחיצה קצרה על כפתור ההפעלה – יופיע מסך הנעילה.","הזינו את קוד הגישה (PIN) שקבעתם, או השתמשו בזיהוי פנים / טביעת אצבע.","אם שכחתם את הקוד: פנו לחנות הסלולר שרכשתם בה את המכשיר לקבלת עזרה."]},
{id:"bas-6",category:"basics",title:"איך מכוונים את עוצמת הקול?",steps:["לחצו על כפתורי הווליום שבצד שמאל של הטלפון: + להגברה, − להנמכה.","במהלך שיחה: אותם כפתורים שולטים בעוצמת הקול של השיחה.","לצלצול: לחצו על כפתורי הווליום כשלא בשיחה כדי לשנות את עוצשת הצלצול.","השתקה מהירה: לחצו פעם אחת על כפתור הווליום המטה בזמן שהטלפון מצלצל – הוא ישתתק."]},
{id:"bas-7",category:"basics",title:"איך מגדילים את הגופן על המסך?",steps:["אנדרואיד: הגדרות > נגישות > גודל גופן וגודל תצוגה > הגדילו לפי הנוחות שלכם.","אייפון: הגדרות > נגישות > תצוגה וגודל טקסט > גודל טקסט מוגדל > הגדילו לפי הנוחות.","ניתן גם להגדיל זמנית כל תמונה או טקסט: הניחו שתי אצבעות על המסך ופרסו אותן (פינץ' החוצה).","לא מוצאים? חפשו את המילה 'נגישות' בתוך תיבת החיפוש של ההגדרות."]},
{id:"bas-8",category:"basics",title:"איך מוצאים אפליקציה שנעלמה?",steps:["החליקו את האצבע כלפי מעלה ממרכז המסך – תיפתח רשימת כל האפליקציות המותקנות.","באנדרואיד: חפשו בתיבת החיפוש שבראש הרשימה את שם האפליקציה.","באייפון: החליקו מטה במסך הבית כדי לפתוח חיפוש > הקלידו את שם האפליקציה.","כדי להחזיר אפליקציה למסך הבית: לחצו לחיצה ארוכה על האייקון שלה > גררו אותה למסך הרצוי."]},
{id:"bas-9",category:"basics",title:"איך חוסכים בסוללה?",steps:["הורידו את בהירות המסך: גררו את מחוון הבהירות (☀️) בווילון העליון כלפי מטה.","כבו Wi-Fi ובלוטות' כשאינכם משתמשים בהם – הם מרוקנים את הסוללה ברקע.","הפעילו מצב חיסכון בסוללה: הגדרות > סוללה > מצב חיסכון.","מסך שנשאר דלוק מרוקן סוללה מהר – הגדירו כיבוי מסך אוטומטי לאחר 30 שניות."]},
{id:"bas-10",category:"basics",title:"מה לעשות אם הטלפון תקוע ולא מגיב?",steps:["המתינו 30 שניות לפני כל פעולה – לפעמים הטלפון פשוט עסוק בעדכון.","הפעלה מחדש כפויה באנדרואיד: לחצו לחיצה ארוכה על כפתור ההפעלה + כפתור הווליום למטה יחד (10 שניות).","הפעלה מחדש כפויה באייפון (עם כפתור בית): לחצו בו-זמנית על כפתור הבית + כפתור ההפעלה עד שיופיע לוגו Apple.","אם הבעיה חוזרת – פנו לסיוע טכני. אל תנסו לפתוח את הטלפון לבד!"]},
{id:"bas-11",category:"basics",title:"כפתורי הניווט בתחתית המסך",steps:["🏠 כפתור הבית — אנדרואיד: עיגול ○ בתחתית המסך. אייפון (ישן): כפתור פיזי עגול מתחת למסך. אייפון (חדש): החליקו מהתחתית למעלה. בכולם: מחזיר מיד למסך הראשי.","◀ כפתור חזרה — אנדרואיד: חץ שמאלה ‹ בתחתית המסך. אייפון: חץ קטן בפינה השמאלית העליונה. בכולם: חוזר שלב אחד אחורה.","⧉ כפתור אפליקציות פתוחות — אנדרואיד: ריבוע □ או שתי מלבניות חופפות בתחתית. אייפון (חדש): החליקו למעלה ועצרו באמצע. גררו אפליקציה הצידה לסגירה.","💡 טיפ: אם נלחץ משהו בטעות ואתם אבודים – לחצו על כפתור הבית ותחזרו תמיד למסך הבטוח!"]},
{id:"bas-12",category:"basics",title:"הסמלים הקטנים בסרגל העליון ופתיחת הווילון",steps:["החליקו את האצבע מהחלק העליון ביותר של המסך כלפי מטה כדי לפתוח את וילון ההגדרות המהירות (שימו לב: הווילון נפתח תמיד בגרירה ישירה מלמעלה למטה, ולא באמצעות לחיצה על שלוש נקודות).","📶 Wi-Fi (גלים או פסים) — פסים מלאים = מחוברים לאינטרנט. פסים חצויים או ✕ = אין חיבור. חיצים 5G/4G = רשת סלולרית.","🔋 סוללה — ירוק = תקין. כתום = מתחת ל-30%. אדום = מתחת ל-10%, טעינה דחופה! ⚡ ברק = הטלפון בטעינה.","🔕 פעמון עם קו = מצב שקט. 🌙 ירח = נא לא להפריע. ✈️ מטוס = מצב טיסה, ללא קליטה כלל.","🔵 Bluetooth = חיבור אלחוטי לאוזניות. 📍 חץ = GPS פעיל. 🔄 שני חצים = סנכרון נתונים ברקע."]},
{id:"bas-13",category:"basics",title:"מחוות מסך – איך לגעת נכון בטלפון?",steps:["👆 לחיצה קצרה (טאפ) — נגיעה אחת מהירה. כך פותחים אפליקציה, לוחצים כפתור, בוחרים פריט.","👇 לחיצה ארוכה — שמירת האצבע על הסמל 2–3 שניות. לרוב פותחת תפריט נוסף עם אפשרויות.","☝️ גלילה (scroll) — הנחת האצבע על המסך וגרירה למעלה לראיית תוכן נוסף, למטה לחזרה.","🤏 פינץ' — הניחו שתי אצבעות: פרסו להגדלה, קרבו להקטנה. עובד בתמונות, מפות, ודפי אינטרנט.","👈 החלקה (swipe) — גרירה מהירה: ימינה/שמאלה לדפדוף בין תמונות, מלמטה למעלה לסגירת אפליקציה."]},
{id:"bas-14",category:"basics",title:"איך מחפשים דברים בתוך הטלפון?",steps:["🔍 אנדרואיד — החליקו מטה על מסך הבית כדי לפתוח תיבת חיפוש. הקלידו שם אפליקציה, איש קשר, או הגדרה.","🔍 אייפון — החליקו מטה ממרכז מסך הבית. תיפתח תיבת חיפוש שמוצאת אפליקציות, אנשי קשר, והגדרות.","⚙️ בתוך ההגדרות — בראש כל מסך הגדרות יש תיבת חיפוש. הקלידו מה שאתם מחפשים במקום לגלול.","💡 לא מוצאים אפליקציה? חפשו את שמה – היא תופיע גם אם הועברה לתיקייה אחרת."]},
{id:"bas-15",category:"basics",title:"מהן 'שלוש הנקודות' או 'הפסים' במסך ובמקלדת?",steps:["בסרגל העליון של אפליקציות (כמו וואטסאפ): שלוש נקודות (⋮) או פסים (☰) הם כפתור 'אפשרויות נוספות'. לחיצה עליהם תפתח הגדרות, אפשרות לעריכה, או יצירת קבוצה.","בווילון העליון של המכשיר: שלוש נקודות בפינה מאפשרות לערוך את כפתורי הקישור המהירים (כמו Wi-Fi או פנס) ולשנות את הסדר שלכם. שימו לב: הווילון עצמו נפתח אך ורק על ידי גרירת האצבע מחלקו העליון של המסך מטה, ולא על ידי לחיצה עליהן.","במקלדת של וואטסאפ: מעל האותיות יש שורה עם שלוש נקודות (•••) או פסים. לחיצה עליהם פותחת תפריט כלים חבוי - כמו תרגום, העתק-הדבק, או שינוי עיצוב המקלדת.","💡 טיפ זהב: בכל פעם שאתם מחפשים הגדרה או כפתור שלא מופיע מיד על המסך - חפשו את שלוש הנקודות! הן תמיד פותחות אפשרויות נוספות חבויות."]},
{id:"bas-16",category:"basics",title:"איך מנקים את מסך המכשיר בצורה בטוחה?",steps:["כבו את מסך הטלפון לפני הניקוי כדי שתוכלו לראות בקלות את כתמי הלכלוך.","השתמשו רק במטלית מיקרופייבר רכה (כמו המטלית לניקוי משקפיים).","אל תתיזו מים או חומרי ניקוי ישירות על המסך! הם עלולים לחלחל פנימה ולגרום נזק.","במידת הצורך, לחלחו מעט את קצה המטלית במים (לא רטובה מדי) ונגבו בעדינות בתנועות מעגליות.","ייבשו את המסך מיד עם הצד היבש של המטלית לפני הדלקתו מחדש."]},
{id:"bas-17",category:"basics",title:"מה לעשות כשמופיעות הודעות אזהרה מבהילות באינטרנט?",steps:["נתקלתם בהודעה קופצת האומרת 'הטלפון שלכם נפרץ' או 'יש לכם וירוס'? אל תיבהלו! זו כמעט תמיד תרמית שמנסה להפחיד אתכם.","אל תלחצו על שום כפתור בתוך ההודעה הזו, ואל תורידו שום אפליקציה שהיא מציעה לכם להתקין.","לחצו מיד על כפתור הבית 🏠 של המכשיר כדי לצאת מהאינטרנט ולסגור את הדפדפן.","פתחו את כפתור האפליקציות האחרונות (□ או החלקה למעלה) וסגרו לחלוטין את אפליקציית האינטרנט שלכם.","במקרה של ספק: אל תזינו פרטי אשראי או פרטים אישיים בשום אתר שמקפיץ הודעות כאלה."]},
{id:"bas-18",category:"basics",title:"איך שולטים במצב רטט, שקט ו'נא לא להפריע'?",steps:["פתחו את וילון ההגדרות המהירות על ידי גרירת האצבע מראש המסך כלפי מטה.","חפשו את סמל הרמקול 🔊.","לחיצה אחת תהפוך אותו למצב רטט 📳 (הטלפון ירטוט בשיחות אך לא ישמיע צלצול).","לחיצה נוספת תעביר למצב השתק מוחלט 🔇.","מצב 'נא לא להפריע' (סמל של מינוס או ירח 🌙): משתיק את כל השיחות וההתראות, אך מאפשר לכם להגדיר שאנשים קרובים מסוימים (כמו הילדים) עדיין יוכלו להשיג אתכם במקרה חירום."]},
{id:"bas-19",category:"basics",title:"מה זה eSIM ואיך מתקינים אותו?",steps:["eSIM הוא כרטיס SIM דיגיטלי שמותקן בתוך הטלפון בלי צורך בכרטיס פיזי קטן שמכניסים לחריץ.","היתרון: אפשר להחזיק שני מספרים בטלפון אחד (למשל מספר ישראלי ומספר זמני בחו\"ל), בלי להחליף כרטיסים פיזית.","באנדרואיד: הגדרות > רשת ואינטרנט (או חיבורים) > SIM-ים > הוסף eSIM > עקבו אחר ההנחיות שמקבלים מחברת הסלולר (לרוב סריקת קוד QR).","באייפון: הגדרות > Cellular (סלולרי) > Add Cellular Plan > סרקו את קוד ה-QR שקיבלתם מחברת הסלולר או הזינו את הפרטים ידנית.","חשוב: כדי לקבל eSIM צריך לפנות לחברת הסלולר (פלאפון, סלקום, פרטנר וכו') ולבקש את הקוד המתאים — לא ניתן ליצור eSIM בעצמכם.","אם המכשיר ישן או לא תומך ב-eSIM, תקבלו הודעת שגיאה — לא כל הדגמים תומכים בטכנולוגיה הזו."]},
{id:"bas-20",category:"basics",title:"איך משפרים קליטה סלולרית עם Wi-Fi Calling?",steps:["Wi-Fi Calling מאפשר לבצע ולקבל שיחות טלפון רגילות באמצעות חיבור האינטרנט האלחוטי (Wi-Fi) שלכם, גם כשהקליטה הסלולרית חלשה (למשל בתוך הבית, מרתף, או באזור מרוחק).","השיחה עדיין נספרת כשיחה רגילה מול חבילת הסלולר שלכם — היא רק 'עוברת' דרך האינטרנט הביתי כשהקליטה חלשה.","באנדרואיד: הגדרות > רשת ואינטרנט > SIM-ים > Wi-Fi Calling > הפעילו את המתג.","באייפון: הגדרות > Cellular (סלולרי) > Wi-Fi Calling > הפעילו את המתג 'Wi-Fi Calling on This iPhone'.","אם האפשרות לא מופיעה בתפריט: ייתכן שחברת הסלולר שלכם לא תומכת בשירות, או שצריך לעדכן את התוכנה במכשיר.","וודאו שאתם מחוברים לרשת Wi-Fi פעילה בבית — אחרת השירות לא יעבוד."]},

// ── וואטסאפ ──────────────────────────────────────────────────────
{id:"wa-1",category:"whatsapp",title:"איך מתקינים ומגדירים את וואטסאפ?",steps:["פתחו את חנות האפליקציות (Google Play באנדרואיד או App Store באייפון).","חפשו בשורה העליונה את המילה: WhatsApp.","לחצו על כפתור התקן והמתינו לסיום ההורדה וההתקנה.","פתחו את האפליקציה והקלידו את מספר הטלפון הנייד שלכם.","הזינו את קוד האימות שקיבלתם בהודעת SMS.","בחרו שם מתאים והוסיפו תמונת פרופיל שלכם."]},
{id:"wa-2",category:"whatsapp",title:"איך שולחים הודעה או מבצעים שיחה?",steps:["היכנסו לאפליקציית אנשי הקשר הרגילה של הטלפון שלכם.","חפשו ובחרו את האדם אליו תרצו להתקשר או לכתוב.","לחצו על כפתור המידע (סמל האות i) שליד שמו.","בחרו בפעולה הרצויה: הודעה, שיחה קולית או שיחת וידאו."]},
{id:"wa-3",category:"whatsapp",title:"איך מקליטים ושולחים הודעה קולית?",steps:["להקלטה קצרה: לחצו לחיצה ארוכה על סמל המיקרופון > דברו אל המכשיר > שחררו את האצבע וההודעה תישלח.","להקלטה ארוכה (בלי להחזיק): לחצו על המיקרופון וגררו את האצבע כלפי מעלה לנעילה.","כשסיימתם לדבר, לחצו על חץ השליחה הירוק."]},
{id:"wa-4",category:"whatsapp",title:"איך שולחים תמונות מהגלריה?",steps:["היכנסו לאפליקציית גלריית התמונות שלכם.","סמנו בנגיעה קלה את התמונה שתרצו לשלוח.","לחצו על סמל השיתוף (חץ קטן או שלוש נקודות מחוברות).","בחרו בסמל של וואטסאפ, סמנו את איש הקשר ואשרו את השליחה."]},
{id:"wa-5",category:"whatsapp",title:"איך משתפים מיקום?",steps:["ודאו שרכיב המיקום (GPS) מופעל במכשיר שלכם.","היכנסו לשיחה של האדם הרצוי בוואטסאפ.","לחצו על סמל הסיכה שליד תיבת כתיבת ההודעה.","בחרו באייקון המיקום ולחצו על שיתוף מיקום."]},
{id:"wa-6",category:"whatsapp",title:"איך מוחקים הודעה שנשלחה בטעות?",steps:["לחצו לחיצה ארוכה על ההודעה שברצונכם למחוק.","בתפריט שייפתח, לחצו על סמל פח האשפה.","בחרו: מחק אצל כולם (זמין לזמן מוגבל בלבד לאחר השליחה)."]},
{id:"wa-7",category:"whatsapp",title:"איך עורכים הודעה שנשלחה? (עד 15 דקות)",steps:["לחצו לחיצה ארוכה על ההודעה שברצונכם לתקן.","לחצו על שלוש הנקודות בסרגל העליון, או על עיפרון העריכה הסרגל העליון.","בחרו באפשרות עריכה.","תקנו את הטקסט ולחצו על סימן ה-V הירוק לאישור.","💡 בגרסת בטא של וואטסאפ: יופיע סמל עיפרון ✏️ ישירות בסרגל העליון של ההודעה הבודדת — לחיצה עליו פותחת את העריכה במקום לעבור דרך שלוש הנקודות."]},
{id:"wa-8",category:"whatsapp",title:"איך מוסיפים קיצור דרך לצ'אט במסך הבית?",steps:["במסך הראשי של וואטסאפ, לחצו לחיצה ארוכה על השיחה הרצויה.","לחצו על שלוש הנקודות בתפריט העליון.","בחרו: הוסף קיצור דרך לצ'אט.","אשרו על ידי לחיצה על הוסף."]},
{id:"wa-9",category:"whatsapp",title:"איך יוצרים רשימת תפוצה?",steps:["במסך הראשי של וואטסאפ, לחצו על שלוש הנקודות בפינה העליונה.","בחרו: רשימת תפוצה חדשה.","צרפו לפחות שני אנשים מרשימת אנשי הקשר.","לחצו על החץ הירוק לסיום – ההודעה תגיע לכל אחד בנפרד."]},
{id:"wa-10",category:"whatsapp",title:"איך מקשרים את וואטסאפ למחשב?",steps:["פתחו את וואטסאפ בטלפון ולחצו על שלוש הנקודות (⋮) בפינה העליונה.","בחרו: מכשירים מקושרים.","לחצו על קשר מכשיר.","פתחו במחשב את הכתובת web.whatsapp.com וסרקו את קוד ה-QR שמופיע עם הטלפון.","מעתה תוכלו לכתוב ולקרוא הודעות ישירות מהמחשב!"]},
{id:"wa-11",category:"whatsapp",title:"איך שולחים מיקום נוכחי ובזמן אמת (מעקב)?",steps:["ודאו שרכיב המיקום (GPS) מופעל בטלפון שלכם (דרך וילון ההגדרות העליון שנפתח בגרירה מטה).","היכנסו לשיחה של האדם שברצונכם לשלוח לו את המיקום בוואטסאפ.","לחצו על סמל הסיכה (📎) או סמל הפלוס (+) שליד שורת כתיבת ההודעה.","בחרו באפשרות 'מיקום' (סמל של סיכה עגולה על גבי מפה).","לשליחת נקודה קבועה ברגע זה: לחצו על 'שלח את מיקומך הנוכחי' (האדם השני יראה בדיוק היכן הייתם כששלחתם והסימון לא ישתנה גם אם תזוזו).","לשיתוף בזמן אמת (מעקב בתנועה): לחצו על 'שתף מיקום בזמן אמת', בחרו את משך הזמן (למשל: שעה אחת) ולחצו על חץ השליחה. המיקום שלכם יתעדכן על המפה של האחר גם כשאתם זזים!"]},
{id:"wa-12",category:"whatsapp",title:"איך מצרפים קובץ, תמונה או מסמך?",steps:["בתוך שיחה, לחצו על סמל הסיכה (📎) שליד שורת כתיבה.","בחרו את סוג הקובץ: תמונה מהגלריה, מסמך (PDF, Word), אנשי קשר, או אודיו.","נווטו לקובץ הרצוי ולחצו עליו לבחירה.","ניתן להוסיף כיתוב קצר ולאחר מכן לחצו על החץ הירוק לשליחה."]},
{id:"wa-13",category:"whatsapp",title:"איך יוצרים קבוצה חדשה?",steps:["לחצו על שלוש הנקודות (⋮) בפינה העליונה ובחרו: קבוצה חדשה.","בחרו את האנשים שתרצו להוסיף לקבוצה מרשימת אנשי הקשר.","לחצו על החץ הירוק, הוסיפו שם לקבוצה ואם תרצו – גם תמונה.","לחצו צור – הקבוצה מוכנה ותוכלו להתחיל לשלוח הודעות לכולם יחד!"]},
{id:"wa-14",category:"whatsapp",title:"איך שומרים ומורידים תמונות וסרטונים לגלריה?",steps:["כברירת מחדל, תמונות שמגיעות אליכם נשמרות אוטומטית בגלריה של הטלפון.","אם זה לא קורה: כנסו לוואטסאפ > לחצו על שלוש הנקודות (⋮) בפינה העליונה > בחרו 'הגדרות'.","כנסו ל'צ'אטים' וודאו שהמתג ליד 'חשיפת מדיה' מופעל (צבוע בירוק).","אם ברצונכם לשמור ידנית תמונה בודדת שקיבלתם: פתחו את התמונה בתוך השיחה.","לחצו על שלוש הנקודות (⋮) בפינה העליונה ובחרו באפשרות 'שמור'. התמונה תופיע כעת באפליקציית הגלריה או התמונות שלכם."]},
{id:"wa-15",category:"whatsapp",title:"איך חוסמים או מדווחים על איש קשר מציק?",steps:["קיבלתם הודעה מאדם שאינכם מכירים או מפרסומת מטרידה? פתחו את השיחה איתם.","לרוב וואטסאפ תציג לכם כפתור מהיר בראש הצ'אט שנקרא 'חסום' או 'דווח וחסום'. לחצו עליו.","אם הכפתור לא מופיע: לחצו על שם השולח או על מספר הטלפון שלו שמופיע בראש השיחה כדי לפתוח את הפרטים שלו.","גללו מטה עד סוף המסך ולחצו על כפתור האדום 'חסום' (Block).","אישור החסימה ימנע מאותו אדם לשלוח לכם הודעות או לראות מתי אתם מחוברים."]},
{id:"wa-16",category:"whatsapp",title:"איך סורקים מסמכים ושולחים אותם כקובץ PDF?",steps:["וואטסאפ כוללת תכונה המאפשרת להשתמש במצלמה כסורק מסמכים מקצועי, לחתוך שוליים אוטומטית ולשלחם כקובץ PDF נקי וקריא.","פתחו את הצ'אט בוואטסאפ של האדם אליו תרצו לשלוח את המסמך.","לחצו על סמל סיכת הנייר (📎) באנדרואיד או על סמל הפלוס (+) באייפון.","בחרו באפשרות 'מסמך' (Document).","בחרו באפשרות 'סריקת מסמך' (Scan Document).","מקמו את מצלמת הטלפון מעל המסמך - המערכת תזהה את השוליים, תיישר אותם ותצלם אוטומטית.","סדרו או חתכו את השוליים באופן ידני לפי הצורך, ואשרו את הצילום.","לחצו על חץ השליחה הירוק - המסמך יישלח כקובץ PDF נקי ומקצועי ללא רקע שולחן העבודה מסביב!"]},
{id:"wa-17",category:"whatsapp",title:"איך מבצעים שיחת וידאו קבוצתית?",steps:["פתחו את לשונית הצ'אטים ובחרו קבוצה קיימת, או צרו קבוצה חדשה עם האנשים שתרצו לכלול בשיחה.","בתוך הקבוצה, לחצו על סמל המצלמה בפינה העליונה של המסך.","כל חברי הקבוצה יקבלו הודעה שמישהו מתקשר, ויוכלו ללחוץ על הכפתור הירוק כדי להצטרף.","ניתן לראות בו-זמנית עד מספר משתתפים מוגבל על המסך (תלוי בדגם הטלפון) — באייפון ואנדרואיד חדשים אפשר לכלול קבוצה גדולה.","לסיום השיחה לכולם: לחצו על הכפתור האדום."]},
{id:"wa-18",category:"whatsapp",title:"איך משתפים מסך בשיחת וידאו בוואטסאפ?",steps:["שיתוף מסך מאפשר להראות לבן השיח מה רואים על המסך שלכם בזמן שיחת וידאו — שימושי כדי להראות הודעה, תמונה או בעיה טכנית.","פתחו שיחת וידאו רגילה (אישית או קבוצתית) בוואטסאפ.","בזמן השיחה, לחצו על סמל שיתוף המסך (לרוב מוצג כריבוע עם חץ, או מופיע בתפריט שלוש הנקודות בתוך השיחה).","אשרו את ההרשאה שמופיעה ('להתחיל שידור או הקלטה') — זה נדרש על ידי המכשיר ולא על ידי וואטסאפ.","כל מה שמופיע על המסך שלכם (כולל הודעות אחרות!) יוצג לבן השיח – סגרו אפליקציות פרטיות לפני השיתוף.","לעצירת השיתוף: לחצו שוב על הסמל, או על ההודעה האדומה שמופיעה בראש המסך."]},
{id:"wa-19",category:"whatsapp",title:"איך שולחים כרטיס איש קשר (שיתוף פרטים אישיים)?",steps:["במקום להקליד מספר טלפון של מישהו, אפשר לשלוח את כל כרטיס איש הקשר בלחיצה אחת.","בתוך שיחה בוואטסאפ, לחצו על סמל הסיכה (📎) או סמל הפלוס (+) שליד שורת הכתיבה.","בחרו באפשרות 'איש קשר' (Contact).","בחרו מתוך רשימת אנשי הקשר שלכם את מי שתרצו לשתף (אפשר לבחור כמה אנשים בבת אחת).","לחצו על השליחה — הצד השני יקבל כרטיס לחיץ שניתן לשמור ישירות לאנשי הקשר שלו.","⚠️ זהירות: שתפו פרטי אנשים אחרים רק באישורם — זה כולל את מספר הטלפון והשם שלהם."]},

// ── אנדרואיד ─────────────────────────────────────────────────────
{id:"and-1",category:"android",title:"איך מורידים ומתקינים אפליקציות?",steps:["פתחו את חנות Google Play (האייקון של המשולש הצבעוני).","הקלידו את שם האפליקציה בתיבת החיפוש העליונה.","בדקו את התוצאות (מומלץ לדלג על שורות שכתוב עליהן 'ממומן').","לחצו על כפתור התקן והמתינו לסיום ההתקנה."]},
{id:"and-2",category:"android",title:"איך מתחברים לרשת Wi-Fi?",steps:["פתחו את ההגדרות (סמל גלגל השיניים).","לחצו על חיבורים (או Wi-Fi).","ודאו שמתג ה-Wi-Fi מופעל.","בחרו את שם הרשת הביתית מהרשימה.","הקלידו את סיסמת הרשת ולחצו התחבר."]},
{id:"and-3",category:"android",title:"איך שומרים ועורכים אנשי קשר?",steps:["לשמירה חדשה: פתחו אנשי קשר > לחצו על + > הקלידו שם ומספר > לחצו שמור.","לעריכה: היכנסו לאיש הקשר הרצוי.","לחצו על סמל העיפרון (עריכה).","עדכנו את הפרטים ולחצו שמור."]},
{id:"and-4",category:"android",title:"איך משנים את שפת המכשיר לעברית?",steps:["פתחו הגדרות > ניהול כללי (או מערכת).","לחצו על שפה וקלט > שפה.","לחצו על הוספת שפה ובחרו עברית.","גררו את עברית אל ראש הרשימה."]},
{id:"and-5",category:"android",title:"איך מוסיפים חשבון גוגל למכשיר?",steps:["פתחו הגדרות > משתמשים וחשבונות (או סיסמאות ומילוי אוטומטי).","לחצו על הוספת חשבון ובחרו Google.","עקבו אחר ההנחיות להזנת כתובת המייל והסיסמה."]},
{id:"and-6",category:"android",title:"איך מנהלים וחוסמים התראות?",steps:["פתחו הגדרות > התראות (או יישומים והתראות).","לחצו על הגדרות אפליקציה ובחרו את האפליקציה המציקה.","כבו את המתג הראשי להפסקת ההתראות."]},
{id:"and-7",category:"android",title:"איך חוסמים מספרים לא רצויים?",steps:["פתחו את אפליקציית הטלפון.","עברו ללשונית אחרונים.","לחצו לחיצה ארוכה על המספר המטריד.","בחרו: חסימה או דיווח על ספאם."]},
{id:"and-8",category:"android",title:"איך מגבים נתונים ומאפסים את המכשיר?",steps:["לגיבוי: הגדרות > שירותי גוגל > גיבוי > הפעילו את הגיבוי.","לאיפוס: ודאו שהסוללה מעל 70% והמכשיר מחובר לאינטרנט.","חפשו 'איפוס' בתיבת החיפוש של ההגדרות.","בצעו איפוס (זהירות: מוחק את כל תוכן המכשיר!)."]},
{id:"and-9",category:"android",title:"איך מגדירים או מבטלים נעילת מסך באנדרואיד?",steps:["להגדרת נעילה חדשה: פתחו את ההגדרות (סמל גלגל השיניים) > לחצו על 'מסך נעילה' (או 'אבטחה ופרטיות').","לחצו על 'סוג נעילת מסך' ובחרו את האפשרות המועדפת עליכם: קוד מספרים (PIN), ציור קו (דפוס) או סיסמה.","הקלידו או ציירו את הקוד שבחרתם פעמיים כדי לוודא שלא טעיתם, ולחצו על אישור.","להוספת טביעת אצבע או זיהוי פנים: בהגדרות כנסו ל'אבטחה' > 'זיהוי ביומטרי' ועקבו אחר ההנחיות לסריקת האצבע או הפנים.","לביטול הנעילה לחלוטין: היכנסו שוב להגדרות > 'מסך נעילה' > 'סוג נעילת מסך' > הקלידו את הקוד הנוכחי שלכם.","בחרו באפשרות 'ללא' או 'החלקה' (שימו לב: ביטול הנעילה מוחק את טביעות האצבע השמורות ומשאיר את הטלפון חשוף לכולם)."]},
{id:"and-10",category:"android",title:"איך מנקים מקום בטלפון כשהזיכרון מלא?",steps:["קיבלתם הודעה שהזיכרון מלא? פתחו את ההגדרות (סמל גלגל השיניים).","חפשו ובחרו בתפריט 'תחזוקת המכשיר' (או 'אחסון').","המכשיר יציג לכם כמה מקום פנוי נותר. לחצו על כפתור 'בצע אופטימיזציה' או 'נקה כעת' כדי למחוק קבצים זמניים ומיותרים שחוסמים את המערכת.","חפשו אפליקציות שאינכם משתמשים בהן יותר: לחצו עליהן לחיצה ארוכה ובחרו 'הסר התקנה'.","מחקו סרטונים כבדים שקיבלתם בוואטסאפ – הם הגורם העיקרי למילוי מהיר של הזיכרון."]},
{id:"and-11",category:"android",title:"איך מעבירים קבצים או תמונות למחשב עם כבל?",steps:["חברו את קצה כבל הטעינה לטלפון, ואת הקצה השני (הגדול יותר) לחברו לשקע ה-USB במחשב שלכם.","פתחו את מסך הטלפון. ייתכן שתקפוץ הודעה השואלת 'האם לאפשר גישה לנתוני המכשיר?'. לחצו על 'אפשר'.","במחשב שלכם, פתחו את תוכנת 'המחשב שלי' (או 'סייר הקבצים').","תחת רשימת הכוננים בצד, תראו את שם הטלפון שלכם (למשל: Galaxy S20). לחצו עליו.","כנסו לתיקייה בשם DCIM ולאחר מכן לתיקיית Camera – שם נמצאות כל התמונות שצילמתם. כעת תוכלו להעתיק אותן ישירות למחשב."]},
{id:"and-12",category:"android",title:"איך מפעילים מצב כהה (Dark Mode)?",steps:["מצב כהה משנה את צבע הרקע של המסך לשחור/כהה — מקל על העיניים בערב ובלילה, וגם חוסך סוללה.","פתחו הגדרות (סמל גלגל השיניים) > חפשו 'תצוגה' (Display).","לחצו על 'מצב כהה' (Dark Mode) או 'ערכת נושא כהה'.","הפעילו את המתג — המסך ישתנה באופן מיידי לרקע כהה עם טקסט בהיר.","טיפ: ניתן גם להגדיר שהמצב הכהה יידלק אוטומטית בשקיעה ויכבה בזריחה."]},
{id:"and-13",category:"android",title:"איך בודקים ומשנים הרשאות אפליקציה?",steps:["הרשאות הן הדברים שאפליקציה מורשית 'לראות' או 'לעשות' במכשיר שלכם — כמו גישה למצלמה, למיקום או לאנשי הקשר.","פתחו הגדרות > חפשו 'אפליקציות' > בחרו את האפליקציה שמעניינת אתכם.","לחצו על 'הרשאות' (Permissions) — תוצג רשימה של כל מה שהאפליקציה מורשית לגשת אליו.","לחצו על הרשאה ספציפית (למשל 'מיקום') כדי לשנות אותה: אפשר, אל תאפשר, או 'שאל בכל פעם'.","אם אפליקציה מבקשת הרשאה שלא הגיונית לתפקידה (למשל אפליקציית מחשבון שמבקשת גישה לאנשי קשר) — זה סימן אזהרה, כדאי לדחות."]},
{id:"and-14",category:"android",title:"איך מוסיפים וידג'ט למסך הבית?",steps:["וידג'ט הוא 'חלון קטן' שמוצג ישירות על מסך הבית ומציג מידע בלי לפתוח את האפליקציה (כמו תאריך, מזג אוויר, או שעון).","לחצו לחיצה ארוכה על מקום ריק במסך הבית (לא על אייקון).","יופיע תפריט קטן — לחצו על 'וידג'טים' (Widgets).","גללו ובחרו את הוידג'ט הרצוי (למשל שעון, לוח שנה, מזג אוויר).","גררו אותו למקום הרצוי במסך הבית, ושחררו את האצבע.","להזזה או הסרה: לחצו לחיצה ארוכה על הוידג'ט וגררו אותו לפח האשפה שמופיע, או למקום אחר."]},

// ── אייפון ───────────────────────────────────────────────────────
{id:"ios-1",category:"iphone",title:"איך מורידים אפליקציות באייפון?",steps:["פתחו את App Store (האות A הלבנה על רקע כחול).","לחצו על לשונית חיפוש (זכוכית מגדלת) בתחתית המסך.","הקלידו את שם האפליקציה.","לחצו על הורד (Get) והמתינו לסיום."]},
{id:"ios-2",category:"iphone",title:"איך משנים את שפת האייפון לעברית?",steps:["הגדרות > General (כללי).","לחצו על Language & Region (שפה ואזור).","לחצו על Add Language ובחרו עברית.","אשרו את עברית כשפה הראשית."]},
{id:"ios-3",category:"iphone",title:"איך מגדירים אבטחה (פנים או אצבע)?",steps:["זיהוי פנים (Face ID): הגדרות > זיהוי פנים וקוד גישה > הגדירו זיהוי פנים > עקבו אחר הוראות המצלמה.","טביעת אצבע (Touch ID): הגדרות > טביעת אצבע וקוד גישה > הוסיפו טביעת אצבע > הניחו את האצבע על כפתור הבית שוב ושוב."]},
{id:"ios-4",category:"iphone",title:"איך מבצעים שיחת FaceTime?",steps:["פתחו את אפליקציית FaceTime או היכנסו לאנשי הקשר.","בחרו את איש הקשר הרצוי.","לחצו על סמל הווידאו לשיחה עם מצלמה, או על סמל הטלפון לשיחה קולית."]},
{id:"ios-5",category:"iphone",title:"איך חוסמים מספרים מציקים באייפון?",steps:["פתחו את אפליקציית הטלפון.","עברו ללשונית אחרונים (Recents).","לחצו על סמל ה-i הכחול ליד המספר הלא מוכר.","גללו מטה ולחצו על: חסום איש קשר זה."]},
{id:"ios-6",category:"iphone",title:"איך מנהלים התראות באייפון?",steps:["הגדרות > עדכונים (Notifications).","בחרו את האפליקציה שברצונכם לנהל.","כבו או הפעילו את מתג העדכונים."]},
{id:"ios-7",category:"iphone",title:"טיפים יומיומיים לאייפון",steps:["ניווט: השתמשו ב-Apple Maps או Google Maps להוראות הגעה.","תשלום: קרבו את המכשיר למסוף בחנות לתשלום מאובטח (Apple Pay).","תזכורות: הגדירו תזכורות לביקורי רופא ומשימות דרך אפליקציית 'תזכורות'.","שיתוף משפחתי: שתפו אפליקציות, מיקום ונתוני בריאות עם בני המשפחה."]},
{id:"ios-8",category:"iphone",title:"איך מגדירים או מבטלים נעילת מסך באייפון?",steps:["להגדרת נעילה חדשה: היכנסו לאפליקציית ההגדרות > גללו מטה ולחצו על 'Face ID וקוד גישה' (או 'Touch ID וקוד גישה').","לחצו על האפשרות 'הפעל קוד גישה' והזינו קוד בן 6 ספרות (או לחצו על 'אפשרויות קוד גישה' כדי לבחור קוד בן 4 ספרות פשוטות יותר).","הקלידו את הקוד פעם נוספת כדי לאשר אותו.","להוספת זיהוי פנים (Face ID) או טביעת אצבע (Touch ID): באותו תפריט לחצו על 'הגדר Face ID' או 'הוסף טביעת אצבע' ועקבו אחר הנחיות המצלמה.","לביטול הנעילה לחלוטין: היכנסו להגדרות > 'Face ID וקוד גישה' > הקלידו את קוד הגישה הנוכחי שלכם.","גללו מעט מטה ולחצו על הכפתור האדום 'כבה את קוד הגישה' ואשרו (שימו לב: ביטול הקוד יבטל גם את השימוש בארנק הדיגיטלי Apple Pay)."]},
{id:"ios-9",category:"iphone",title:"איך מנקים מקום באייפון ובאחסון ה-iCloud?",steps:["פתחו את הגדרות המכשיר > לחצו על השם שלכם בראש המסך.","לחצו על iCloud כדי לראות מה תופס לכם מקום (בדרך כלל גיבויי תמונות ישנים).","לחצו על 'נהל את אחסון החשבון' כדי למחוק קבצים שאין לכם צורך בהם.","כדי לנקות מקום פיזי באייפון עצמו: חזרו להגדרות הראשיות > 'כללי' > 'שטח אחסון ב-iPhone'.","המכשיר יציג המלצות לחיסכון במקום כמו מחיקה אוטומטית של שיחות ישנות או הסרת אפליקציות שאינן בשימוש."]},
{id:"ios-10",category:"iphone",title:"איך פותחים ומשתמשים במרכז הבקרה באייפון?",steps:["באייפון ללא כפתור בית (דגמים חדשים): החליקו את האצבע כלפי מטה מהפינה הימנית העליונה של המסך (איפה שסמל הסוללה).","באייפון עם כפתור בית: החליקו את האצבע מחלקו התחתון ביותר של המסך כלפי מעלה.","במרכז הבקרה תמצאו קיצורי דרך מהירים ושימושיים ביותר.","סמל הפנס 🔦: לחיצה אחת תפעיל את פנס הטלפון, לחיצה ארוכה תאפשר לשנות את עוצמת האור.","סמל המחשבון או המצלמה: פותח ישירות את הכלים האלו מבלי לחפש אותם במסכים."]},
{id:"ios-11",category:"iphone",title:"איך משתמשים ב-AirDrop להעברת קבצים?",steps:["AirDrop מאפשר להעביר תמונות, סרטונים או קבצים לאייפון אחר הנמצא קרוב פיזית, בלי כבלים ובלי אינטרנט.","ודאו ששני המכשירים (השולח והמקבל) דולקים, קרובים זה לזה (עד כמה מטרים), ושה-Bluetooth וה-Wi-Fi מופעלים בשניהם.","פתחו את התמונה או הקובץ שתרצו לשלוח > לחצו על סמל השיתוף (ריבוע עם חץ למעלה).","בחרו ב-AirDrop מהרשימה — יופיעו שמות המכשירים הקרובים שניתן לשלוח אליהם.","לחצו על שם המכשיר הרצוי. בצד המקבל תופיע הודעה לאישור הקבלה.","אם אינכם רואים מכשירים: בדקו בהגדרות > כללי > AirDrop, שההגדרה היא 'כולם' או 'אנשי קשר בלבד' ולא 'קבל: כבוי'."]},
{id:"ios-12",category:"iphone",title:"איך משתמשים ב-Find My (מצא את האייפון שלי)?",steps:["Find My עוזר לאתר אייפון שאבד או נגנב, ולראות איפה הוא נמצא על מפה.","חשוב: הפעלה מוקדמת! היכנסו להגדרות > השם שלכם בראש המסך > Find My > ודאו שהמתג 'Find My iPhone' מופעל מראש (לפני שהמכשיר אובד).","אם המכשיר אבד: מבן משפחה אחר, היכנסו לאפליקציית Find My באייפון אחר שלהם, או לאתר icloud.com/find בדפדפן.","התחברו עם חשבון ה-Apple ID שלכם — תוצג מפה עם מיקום המכשיר האבוד (אם הוא מחובר לאינטרנט).","אפשרויות: 'השמע צליל' (אם הוא קרוב בבית), 'מצב אבדה' (נועל את המכשיר מרחוק), או 'מחק אייפון' (כפעולה אחרונה אם לא ניתן להשיבו).","💡 טיפ: כדאי לבקש מבן משפחה לשמור את פרטי ההתחברות שלכם ל-Apple ID למקרה חירום כזה."]},
{id:"ios-13",category:"iphone",title:"איך מוסיפים וידג'ט למסך הבית באייפון?",steps:["וידג'ט הוא 'חלון קטן' שמציג מידע ישירות על מסך הבית בלי לפתוח את האפליקציה (כמו תאריך, מזג אוויר או שעון).","לחצו לחיצה ארוכה על מקום ריק במסך הבית עד שהאייקונים מתחילים לרטוט.","לחצו על סמל ה-+ שמופיע בפינה השמאלית העליונה.","חפשו וידג'ט רצוי (למשל מזג אוויר, שעון, לוח שנה) ובחרו את הגודל המתאים.","לחצו 'הוסף וידג'ט' (Add Widget) — הוא יתווסף למסך הבית, אפשר לגרור אותו למקום הרצוי.","לסיום: לחצו 'בוצע' (Done) בפינה העליונה."]},

// ── Gmail ─────────────────────────────────────────────────────────
{id:"gmail-1",category:"gmail",title:"איך פותחים חשבון Gmail חדש?",steps:["פתחו gmail.com בדפדפן או את אפליקציית Gmail.","לחצו על צור חשבון > לשימוש אישי.","הקלידו שם פרטי ושם משפחה.","בחרוכתובת מייל (למשל: שמכם ושנת הלידה).","הגדירו סיסמה חזקה (לפחות 8 תווים עם מספרים ואותיות).","הזינו מספר טלפון לאימות וקבלו קוד ב-SMS.","אשרו את תנאי השירות – החשבון מוכן!"]},
{id:"gmail-2",category:"gmail",title:"איך כותבים ושולחים מייל?",steps:["פתחו Gmail ולחצו על כפתור הכתיבה (עיגול צבעוני עם עיפרון).","בשדה אל (To): הקלידו את כתובת המייל של הנמען.","בשדה נושא: כתבו במילים קצרות על מה עוסק המייל.","כתבו את תוכן ההודעה בשטח הלבן הגדול.","לחצו על חץ השליחה לשליחה."]},
{id:"gmail-3",category:"gmail",title:"איך מצרפים תמונה או קובץ למייל?",steps:["בזמן כתיבת מייל, לחצו על סמל המהדק (📎).","בחרו: צרף קובץ – תיפתח הגלריה או מנהל הקבצים.","בחרו את תמונה או הקובץ הרצוי.","ודאו שהקובץ הצטרף ולחצו שלח."]},
{id:"gmail-4",category:"gmail",title:"איך קוראים ומשיבים על מייל?",steps:["מיילים חדשים מופיעים בגופן מודגש בתיבת הדואר הנכנס.","לחצו על המייל שברצונכם לקרוא.","לחצו על כפתור השב (חץ מעוקל) בתחתית ההודעה.","כתבו את תשובתכם ולחצו שלח."]},
{id:"gmail-5",category:"gmail",title:"איך מוחקים מיילים ומסדרים את תיבת הדואר?",steps:["לחצו לחיצה ארוכה על המייל למחיקה – יופיע סימן ביקורת.","ניתן לסמן מיילים נוספים בלחיצה עליהם.","לחצו על פח האשפה בסרגל העליון.","למחיקה לצמיתות: היכנסו לתיקיית האשפה ולחצו ריקון."]},
{id:"gmail-6",category:"gmail",title:"איך מבטלים מנויים לדואר זבל?",steps:["פתחו מייל פרסומי שמגיע לעתים קרובות.","גללו עד לתחתית המייל.","מצאו את הקישור: הסרה מרשימת תפוצה (Unsubscribe).","לחצו עליו ואשרו – לא תקבלו יותר הודעות מאותו שולח."]},
{id:"gmail-7",category:"gmail",title:"איך מזהים מיילים מסוכנים וניסיונות הונאה?",steps:["מיילים של בנקים, דואר ישראל או חברות אשראי המבקשים מכם להיכנס לקישור ולעדכן פרטים באופן דחוף הם לרוב ניסיונות הונאה!","בדקו תמיד את כתובת השולח: לחצו על שם השולח בראש המייל כדי לראות את הכתובת האמיתית. אם היא נראית כמו ג'יבריש או לא תואמת לאתר הרשמי, מחקו את המייל מיד.","בנקים ודואר ישראל לעולם לא יבקשו מכם סיסמאות או פרטי כרטיס אשראי מלאים בהודעת מייל.","לעולם אל תלחצו על קישורים המבטיחים לכם זכייה בפרסים או הגרלות שלא נרשמתם אליהן.","במקרה של ספק: התקשרו ישירות לשירות הלקוחות הרשמי של החברה, אל תשתמשו במספר הטלפון שמופיע במייל החשוד."]},

// ── צילום ────────────────────────────────────────────────────────
{id:"cam-1",category:"camera",title:"איך פותחים את המצלמה ומצלמים?",steps:["פתחו את אפליקציית המצלמה מהמסך הראשי, או החליקו שמאלה ממסך הנעילה.","לחצו קלות על נושא הצילום במסך – המצלמה תתמקד בו.","לחצו על כפתור הצילום הגדול (עיגול לבן) או על לחצן הווליום.","התמונה נשמרת אוטומטית בגלריה."]},
{id:"cam-2",category:"camera",title:"איך מצלמים סלפי?",steps:["פתחו את אפליקציית המצלמה.","לחצו על סמל ההפיכה (שתי חצים מעגליים) – המצלמה תתהפך לצד הפנים.","הרימו את הטלפון קצת מעל גובה הפנים.","לחצו על כפתור הצילום או השתמשו בטיימר של 3 שניות."]},
{id:"cam-3",category:"camera",title:"איך מצלמים וידאו?",steps:["פתחו את המצלמה והחליקו לבחירת מצב וידאו.","לחצו על כפתור האדום להתחלת הצילום.","החזיקו את הטלפון בשתי ידיים ביציבות.","לחצו שוב על האדום לסיום – הסרטון נשמר אוטומטית."]},
{id:"cam-4",category:"camera",title:"איך מגדילים (זום) בזמן צילום?",steps:["הניחו שתי אצבעות על המסך ופרסו אותן (פינץ' החוצה) להגדלה.","לחלופין: לחצו על כפתורי 1x / 2x / 5x בתחתית המסך.","שימו לב: זום דיגיטלי מוריד את חדות התמונה – עדיף להתקרב פיזית."]},
{id:"cam-5",category:"camera",title:"איך מוצאים ומשתפים תמונות?",steps:["פתחו את אפליקציית הגלריה (או תמונות).","לחצו על התמונה שברצונכם לשתף.","לחצו על סמל השיתוף (חץ למעלה או שלוש נקודות).","בחרו את האפליקציה לשיתוף: וואטסאפ, מייל וכו'."]},
{id:"cam-6",category:"camera",title:"טיפים לצילום טוב יותר",steps:["תאורה היא הכל: צלמו ליד חלון עם אור טבעי.","יציבות: החזיקו את הטלפון בשתי ידיים והצמידו המרפקים לגוף.","נקו את העדשה: קנחו בעדינות את עדשת המצלמה לפני צילום חשוב.","מצב פורטרט: מטשטש את הרקע ומבליט את האדם.","אל תשתמשו בפלאש בפנים – עדיפה תאורת חדר טבעית."]},
{id:"cam-7",category:"camera",title:"איך סורקים קוד ריבוע (QR) בעזרת המצלמה?",steps:["קוד ריבוע (קוד QR) הוא ציור של משבצות שחורות קטנות המופיע על גבי תפריטים במסעדות, עלונים או שלטים.","פתחו את אפליקציית המצלמה הרגילה שלכם (אין צורך להוריד שום אפליקציה נוספת!).","כוונו את המצלמה ישירות אל הקוד, כך שהוא יופיע במרכז המסך (אין צורך לצלם תמונה).","לאחר שנייה, המצלמה תזהה את הקוד ותציג קישור צהוב או כחול קטן על גבי המסך.","לחצו על הקישור שמופיע – הטלפון ייפתח ישירות את אתר האינטרנט או התפריט המבוקש."]},

// ── ניווט ────────────────────────────────────────────────────────
{id:"nav-1",category:"nav",title:"איך מתקינים ומפעילים את Waze?",steps:["הורידו את Waze מ-Google Play או App Store – חינמי לחלוטין.","פתחו ואשרו גישה למיקום שלכם (חיוני לניווט).","הכינו אוזניות או חברו לרמקול הרכב לקבלת הנחיות קוליות.","ודאו שיש חיבור אינטרנט לפני תחילת הנסיעה."]},
{id:"nav-2",category:"nav",title:"איך מנווטים ליעד ב-Waze?",steps:["פתחו Waze ולחצו על סמל החיפוש (זכוכית מגדלת).","הקלידו את כתובת היעד בעברית.","בחרו את הכתובת מהרשימה.","לחצו על לך! (Go!) – Waze יחשב את המסלול ויתחיל להנחות."]},
{id:"nav-3",category:"nav",title:"איך מדווחים על תאונה או פקק ב-Waze?",steps:["לחצו על סמל הדיווח (עיגול עם סימן קריאה) בתחתית המסך.","בחרו את סוג הדיווח: תאונה, פקק, מהמורה, מצלמת מהירות.","אשרו – הדיווח יישלח לכל הנהגים מאחוריכם.","חשוב: דווחו רק כשהרכב עצור!"]},
{id:"nav-4",category:"nav",title:"איך מנווטים ב-Google Maps?",steps:["פתחו את Google Maps.","הקלידו את היעד בשורת החיפוש.","בחרו את המקום מהרשימה ולחצו על כפתור הניווט (חץ כחול).","בחרו מסלול מהאפשרויות ולחצו התחל (Start)."]},
{id:"nav-5",category:"nav",title:"איך שומרים מיקום מועדף ב-Google Maps?",steps:["חפשו את המקום הרצוי (בית חולים, רופא, קניון).","לחצו על שם המקום בתחתית המסך.","לחצו על סמל הכוכב (שמור).","בפעם הבאה: לחצו על שמור (Saved) בתפריט התחתי."]},
{id:"nav-6",category:"nav",title:"איך מוצאים עסקים קרובים?",steps:["פתחו Google Maps ולחצו על שורת החיפוש.","הקלידו מה שאתם מחפשים: בית מרקחת, בנק, רופא.","תופיע מפה עם כל המקומות הקרובים ושעות הפתיחה.","לחצו על מקום לקבלת כתובת ומספר טלפון, ואז על ניווט להגעה."]},
{id:"nav-7",category:"nav",title:"איך מוצאים היכן חנינו את הרכב?",steps:["בעזרת Google Maps: כשאתם מחנים את הרכב, פתחו את האפליקציה ולחצו על הנקודה הכחולה המציגה את מיקומכם הנוכחי על המפה.","ייפתח תפריט קטן בתחתית. לחצו על 'שמור את מיקום החניה' (Save parking).","יופיע סמל של סיכה אדומה עם האות P על המפה שלכם.","בסיום הסידורים, פתחו שוב את האפליקציה ולחצו על הסיכה כדי לדעת בדיוק איך לחזור לרכב שלכם."]},

// ── זום ──────────────────────────────────────────────────────────
{id:"zoom-1",category:"zoom",title:"איך מתקינים ומגדירים את זום?",steps:["הורידו את Zoom מ-Google Play או App Store – חינמי.","פתחו ולחצו על הירשם בחינם (Sign Up Free).","הזינו כתובת מייל וסיסמה, ואשרו את המייל.","אשרו גישה למצלמה ולמיקרופון כשהאפליקציה תבקש."]},
{id:"zoom-2",category:"zoom",title:"איך מצטרפים לפגישה עם קישור?",steps:["קיבלתם קישור בוואטסאפ או מייל? לחצו עליו ישירות.","האפליקציה תיפתח ותכניס אתכם לפגישה אוטומטית.","לחצו על הצצרף עם אודיו המכשיר לשמוע ולהישמע.","תראו את המשתתפים ותוכלו להתחיל לשוחח."]},
{id:"zoom-3",category:"zoom",title:"איך מצטרפים לפגישה עם קוד?",steps:["פתחו Zoom ולחצו על הצטרף לפגישה (Join a Meeting).","הקלידו את מספר הפגישה (9-11 ספרות).","הקלידו את הסיסמה אם נדרש.","לחצו הצטרף (Join) ואשרו את גישת האודיו."]},
{id:"zoom-4",category:"zoom",title:"איך שולטים בקול ובמצלמה בשיחה?",steps:["🎙 מיקרופון בתחתית: לחצו להשתקה (קו אדום) – שימושי כשיש רעשי רקע.","📹 מצלמה בתחתית: לחצו לכיבוי/הפעלה של הווידאו שלכם.","אם לא שומעים אתכם: בדקו שהמיקרופון לא מושתק.","לסיום: לחצו על עזוב (Leave) האדום ואשרו."]},
{id:"zoom-5",category:"zoom",title:"איך פותחים פגישת זום עצמאית?",steps:["פתחו Zoom ולחצו על פגישה חדשה (New Meeting).","לחצו על התחל וידאו (Start with Video).","להזמנת אחרים: לחצו על משתתפים (Participants) > הזמן (Invite).","שלחו את הקישור לחברים דרך וואטסאפ או מייל."]},
{id:"zoom-6",category:"zoom",title:"מה לעשות כשיש בעיות טכניות בזום?",steps:["לא שומעים: ודאו שהווליום גבוה והמיקרופון לא מושתק.","לא רואים: לחצו על סמל המצלמה ובדקו שנתתם גישה בהגדרות.","שיחה קופאת: בדקו חיבור אינטרנט. צאו והצטרפו מחדש.","לא מוצאים כפתורים: הקישו פעם אחת במרכז המסך – הסרגלים יופיעו."]},
{id:"zoom-7",category:"zoom",title:"איך משתיקים את עצמנו ומכבים וידאו?",steps:["השתקה (Mute): לחצו על סמל המיקרופון בתחתית המסך – יופיע קו אדום שמסמן שאתם מושתקים. שימושי כשאתם לא מדברים כדי למנוע רעשי רקע.","ביטול השתקה: לחצו שוב על המיקרופון להסרת ההשתקה וחזרה לשיחה.","כיבוי וידאו (Stop Video): לחצו על סמל המצלמה בתחתית – תיעלמו מהמסך של האחרים ותראו תמונה או שם במקומכם.","אם מנהל הפגישה השתיק אתכם: תופיע הודעה. לחצו על unmute כדי לבקש לדבר או להפעיל את המיקרופון בעצמכם."]},
{id:"zoom-8",category:"zoom",title:"איך מנהלים את המשתתפים בפגישה?",steps:["לחצו על Manage Participants בתחתית המסך – תיפתח רשימה של כל המשתתפים בפגישה.","ניתן לראות ליד כל שם אם המיקרופון שלו פעיל או מושתק, ואם המצלמה שלו דולקת.","לחצו על שם של משתתף כדי לקבל אפשרויות: להשתיק אותו, להסיר אותו מהפגישה, או לתת לו לדבר.","כדי להשתיק את כולם בבת אחת: לחצו Mute All בתחתית הרשימה.","כדי לאפשר לכולם לדבר: לחצו Unmute All."]},
{id:"zoom-9",category:"zoom",title:"איך משתפים מסך בפגישת זום?",steps:["לחצו על Share Screen בתחתית המסך בזמן הפגישה.","יופיע חלון שמציג את כל המסכים והחלונות הפתוחים במחשב שלכם – בחרו מה לשתף.","המשתתפים יראו בדיוק את מה שאתם רואים על המסך שבחרתם.","כדי לעצור את השיתוף: לחצו על Stop Share (כפתור אדום שמופיע בראש המסך).","חשוב לסגור לפני הפגישה חלונות פרטיים שאינכם רוצים שיראו!"]},
{id:"zoom-10",category:"zoom",title:"איך מתכתבים בתוך הפגישה (צ'אט)?",steps:["לחצו על Chat בסרגל התחתון של זום – תיפתח תיבת הצ'אט בצד המסך.","כתבו את ההודעה שלכם בשורה התחתונה של הצ'אט ולחצו Enter לשליחה.","ניתן לשלוח הודעה לכולם, או לבחור שם ספציפי כדי לשלוח הודעה פרטית רק לאותו אדם.","בצ'אט ניתן גם להעביר קבצים לכל המשתתפים – שימושי להעברת מסמכים או קישורים."]},
{id:"zoom-11",category:"zoom",title:"איך מקליטים פגישת זום?",steps:["רק מנהל הפגישה (המארח) יכול להתחיל הקלטה – אם אתם מנהלים, לחצו על Record בסרגל התחתון.","ההקלטה תישמר אוטומטית על המחשב האישי שלכם לאחר סיום הפגישה.","המשתתפים יקבלו הודעה שהפגישה מוקלטת – לא ניתן להקליט בסתר.","לסיום ההקלטה: לחצו על Stop Recording לפני שתסיימו את הפגישה.","לאחר סיום הפגישה, התוכנה תמיר את ההקלטה לקובץ וידאו (MP4) – זה עשוי לקחת כמה דקות."]},
{id:"zoom-12",category:"zoom",title:"איך משתמשים בתגובות ובהצבעות בפגישה?",steps:["לחצו על Reactions בסרגל התחתון – תיפתח רשימת אימוג'ים ותגובות.","בחרו תגובה כמו 👍 👏 ❤️ – היא תופיע על המסך שלכם לכמה שניות ותיראה לכל המשתתפים.","תגובות שימושיות ל'כן/לא' מהיר, לתשואות, או לאישור שהבנתם – בלי לנתק את הדובר.","המארח יכול גם לפתוח הצבעה רשמית – תופיע הודעה על המסך שלכם ותוכלו לבחור את תשובתכם."]},
{id:"zoom-13",category:"zoom",title:"איך יוצאים מהפגישה ואיך המארח סוגר אותה?",steps:["כדי לצאת מהפגישה: לחצו על הכפתור האדום Leave בפינת המסך.","אם אתם משתתפים רגילים – תצאו לבד והפגישה תמשיך לאחרים.","אם אתם המארחים (המזמינים) – תישאלו אם ברצונכם לצאת בלבד (Leave) או לסגור את הפגישה לכולם (End Meeting for All).","לפני הסגירה: ודאו שהסיום נוח לכל המשתתפים וציינו זאת מראש בשיחה."]},
{id:"zoom-14",category:"zoom",title:"מי יכול להצטרף לפגישה, ומי פותח אותה? (משתמש מול מנהל)",steps:["משתתף רגיל: מצטרף לפגישה שמישהו אחר פתח – באמצעות קישור או מספר פגישה. אינו צריך הרשאות מיוחדות.","מנהל הפגישה (host): מי שלחץ על 'פגישה חדשה' (New Meeting) ופתח אותה. רק הוא שולט בהגדרות, בהקלטה, ובסגירת הפגישה לכולם.","ניתן להחליף מנהל בזמן הפגישה: לחצו על Participants > בחרו משתתף > Make Host. שימושי אם המנהל המקורי צריך לצאת.","טיפ: גם משתתף רגיל וגם מנהל יכולים לשתף מסך, להגיב, ולדבר – ההבדל הוא רק בשליטה הכללית על הפגישה."]},
{id:"zoom-15",category:"zoom",title:"איך קובעים רקע וירטואלי לפגישה?",steps:["לחצו על החץ הקטן ▲ ליד סמל המצלמה בתחתית המסך.","בחרו Choose Virtual Background (בחר רקע וירטואלי).","בחרו אחת מהתמונות המוכנות, או לחצו על + כדי להעלות תמונה משלכם מהמכשיר.","ניתן גם לבחור Blur כדי לטשטש את הרקע האמיתי בלי להחליפו לתמונה.","טיפ: רקע אחיד מאחוריכם בחיים האמיתיים (כמו קיר) משפר את האפקט אם המצלמה שלכם חלשה."]},
{id:"zoom-16",category:"zoom",title:"איך משנים שם ותמונה — באפליקציה בטלפון?",steps:["שינוי שם לפגישה נוכחית בלבד: לחצו על Participants > הקישו על שמכם > Rename.","שינוי קבוע: פתחו את האפליקציה > לחצו על Settings (⚙️) בתחתית > לחצו על שמכם בראש המסך.","במסך הפרופיל לחצו על השם לעריכה, ועל העיגול/תמונה כדי להוסיף או להחליף תמונת פרופיל מהגלריה.","שמרו את השינויים – הם יחולו על כל הפגישות הבאות באותו חשבון."]},
{id:"zoom-16b",category:"zoom",title:"איך משנים שם ותמונה — במחשב?",steps:["שינוי שם לפגישה נוכחית בלבד: לחצו על Participants > העבירו עכבר על שמכם > More > Rename.","שינוי קבוע באפליקציית המחשב: לחצו על תמונת הפרופיל בפינה העליונה > Settings > Profile > Edit My Profile (יפתח דפדפן).","שינוי קבוע באתר: היכנסו לאתר zoom.us > Profile > לחצו על Edit ליד השם, ועל Change ליד התמונה.","העלו תמונה מהמחשב ושמרו – השינויים יסתנכרנו אוטומטית לאפליקציה."]},
{id:"zoom-17",category:"zoom",title:"אילו אפשרויות השתתפות יש בפגישה? (קבצים, אינטרנט ועוד)",steps:["שיתוף קבצים: בתוך הצ'אט (Chat) ניתן ללחוץ על סמל הנמלית/קליפס ולבחור קובץ מהמכשיר לשליחה לכולם.","חיבור לאינטרנט: פגישת זום דורשת חיבור אינטרנט פעיל (Wi-Fi מומלץ). חיבור חלש עלול לגרום לקיפאון או ירידה באיכות הווידאו.","שמיעה בלבד: אם אין מצלמה או שאתם מעדיפים – ניתן להצטרף עם אודיו בלבד, בלי להפעיל וידאו.","שיתוף מסך מוגבל: המנהל יכול להגביל מי מורשה לשתף מסך – בתפריט Security > Share Screen.","נעילת הפגישה: המנהל יכול לנעול את הפגישה (Security > Lock Meeting) כך שלא יוכלו להצטרף משתתפים נוספים."]},
{id:"zoom-18",category:"zoom",title:"מה זה חדרים נפרדים (Breakout Rooms) ואיך פותחים אותם?",steps:["חדרים נפרדים מאפשרים לפצל את כל המשתתפים לקבוצות קטנות שמשוחחות בנפרד, ולחזור אח''כ למפגש המרכזי.","רק המנהל (host) יכול לפתוח חדרים: לחצו על Breakout Rooms בסרגל התחתון.","בחרו כמה חדרים ליצור, וכיצד לחלק את המשתתפים: אוטומטית (זום מחלק בעצמו), או ידנית (אתם בוחרים מי הולך לאיזה חדר).","ניתן להגדיר מראש זמן לחדרים, ספירה לאחור לפני סגירה, והודעה שתישלח לכל המשתתפים.","לחצו על Open All Rooms כדי לשלוח את כולם לחדרים – כל משתתף יקבל הודעת הצטרפות וייכנס לחדר שלו."]},
{id:"zoom-19",category:"zoom",title:"איך מנהלים זמן וחוזרים מהחדרים הנפרדים?",steps:["לפני הפיצול לחדרים: תנו משימה קצרה וברורה לכל הקבוצות, כדי שידעו על מה לדבר.","קבעו מראש כמה זמן יוקדש לחדרים (למשל 5, 10 או 15 דקות) ושלחו תזכורת קצת לפני הסיום.","אם אתם המנהלים ורוצים לעזור לקבוצה מסוימת: לחצו על Breakout Rooms > בחרו את החדר > Join.","לסיום: המנהל לוחץ על Close All Rooms – לכל המשתתפים תופיע ספירה לאחור קצרה ואז יוחזרו אוטומטית למפגש הראשי.","טיפ: משפט מוכן להנחיה – \"עכשיו נתחלק לחדרים נפרדים ל-10 דקות. בבקשה להישאר ממוקדים, ובדקה האחרונה נסיים ונחזור למליאה.\""]},

// ── בינה מלאכותית ──────────────────────────────────────────────────
{id:"ai-1",category:"ai",title:"מה זה בכלל בינה מלאכותית?",steps:["בינה מלאכותית (או AI) היא תוכנת מחשב חכמה שמסוגלת להבין שפה חופשית וטבעית ולענות כמו בן אדם.","היא לא אדם אמיתי, אין לה רגשות, והיא לא חושבת כמונו - היא פשוט סורקת כמויות אדירות של מידע בשניות ומנסחת תשובה מתאימה.","אפשר לדבר איתה בצ'אט (כמו וואטסאפ) ולבקש ממנה לכתוב, לתרגם, לתקן או להסביר דברים פשוטים.","הכלים הנפוצים והחינמיים ביותר כיום הם ChatGPT של חברת OpenAI, ו-Gemini של חברת Google."]},
{id:"ai-2",category:"ai",title:"איך לשאול שאלות ולקבל תשובות מעולות?",steps:["דברו עם הבינה המלאכותית כאילו אתם מדברים עם עוזר אישי סבלני במיוחד.","היו מפורטים: במקום לכתוב 'מתכון לעוגה', כתבו 'תן לי מתכון פשוט לעוגת שוקולד ללא גלוטן בתוך 5 דקות'.","הסבירו לה מי אתם ומה אתם צריכים: למשל, 'אני סבא שרוצה לכתוב ברכה מרגשת לנכד שלי שחוגג יום הולדת 10, תן לי 3 אפשרויות'.","בקשו ממנה לפשט דברים: אם התשובה ארוכה או מסובכת מדי, כתבו לה 'הסבר לי את זה שוב במילים פשוטות ובשלבים קצרים'."]},
{id:"ai-3",category:"ai",title:"זהירות מהמצאות - הבינה המלאכותית לפעמים טועה!",steps:["למרות שהיא נשמעת בטוחה בעצמה, הבינה המלאכותית עלולה להמציא עובדות, תאריכים או שמות (תופעה זו נקראת 'הזיה').","תמיד בדקו מידע קריטי: אם מדובר במידע רפואי, עצות משפטיות או החלטות פיננסיות, אל תסתמכו על הבינה המלאכותית בלבד ובדקו תמיד מול בעל מקצוע או אתר רשמי.","היא לא מעודכנת בהכל: חלק מכלי הבינה המלאכותית לא מחוברים לאינטרנט בזמן אמת ולכן עלולים לא להכיר אירועים חדשים שקרו לאחרונה."]},
{id:"ai-4",category:"ai",title:"שמירה על פרטיות - מה אסור לשתף?",steps:["הבינה המלאכותית לומדת מההודעות שלכם וכל מה שאתם כותבים נשמר בשרתים שלה.","לעולם אל תכתבו פרטים אישיים רגישים: אל תשתפו מספרי תעודת זהות, פרטי כרטיס אשראי, סיסמאות או מידע רפואי אישי ואינטימי.","השתמשו בשמות כלליים: אם אתם רוצים לנסח מכתב רשמי, כתבו 'פלוני אלמוני' במקום את שמכם האמיתי, והחליפו את הפרטים האמיתיים לאחר שהתוכנה תסיים לנסח את המכתב עבורכם."]},
{id:"ai-5",category:"ai",title:"רעיונות מדליקים: במה הבינה המלאכותית יכולה לעזור?",steps:["ניסוח מכתבים רשמיים: בקשו ממנה 'נסח לי מכתב רשמי ומכובד לחברת החשמל המבקש לבדוק חיוב שגוי'.","רעיונות למתכונים: כתבו לה 'יש לי במקרר רק עגבניות, בצל וגבינה צהובה, מה אפשר להכין מזה?' ותקבלו רעיונות מיידיים.","תרגום ולימוד שפות: בקשו ממנה לתרגם משפטים לאנגלית או לכל שפה אחרת, או לתרגל איתכם שיחה קלה באנגלית.","תקצירי ספרים וסרטים: בקשו ממנה לסכם לכם ספר או להמליץ על סרטים דומים לסרטים שאהבתם."]},
{id:"ai-6",category:"ai",title:"איך מבקשים מהבינה המלאכותית לכתוב מכתב למשרד ממשלתי?",steps:["פתחו את אפליקציית הבינה המלאכותית (כמו ChatGPT או Gemini) וכתבו בקשה מפורטת: 'אני צריך לכתוב מכתב רשמי לביטוח הלאומי בנושא X, נסח לי טיוטה מנומסת ומכבדת'.","ציינו את כל הפרטים החשובים: מה הבעיה, מה הבקשה שלכם, ומה התוצאה שאתם רוצים.","קראו את הטיוטה שתקבלו, ותקנו פרטים אם צריך (למשל שם, תאריך, מספר תיק).","זכרו: אל תכתבו בהודעה לבינה המלאכותית פרטים רגישים כמו מספר תעודת זהות מלא — השתמשו ב'XXXXX' והשלימו את הפרט בעצמכם בטיוטה הסופית."]},
{id:"ai-7",category:"ai",title:"איך מבקשים מהבינה המלאכותית רשימת קניות או תזכורות?",steps:["כתבו לבינה המלאכותית במשפט פשוט: 'אני צריך להכין מרק עוף וסלט ירקות, תן לי רשימת קניות מסודרת לפי מחלקות בסופר'.","אפשר גם לבקש: 'תכין לי רשימת תזכורות שבועית לתרופות שאני צריך לקחת בבוקר ובערב'.","הבינה המלאכותית תכתוב רשימה מאורגנת – אפשר להעתיק אותה (לחיצה ארוכה על הטקסט > העתק) ולשלוח לעצמכם בוואטסאפ כדי שתהיה נגישה בסופר.","טיפ: בקשו רשימה 'קצרה וממוספרת' אם התשובה יוצאת ארוכה ומסובכת מדי."]},
{id:"ai-8",category:"ai",title:"איך מבקשים מהבינה המלאכותית לתרגם תפריט או שלט?",steps:["נתקלתם בתפריט או שלט בשפה זרה בנסיעה בחו\"ל? צלמו אותו עם המצלמה.","פתחו את אפליקציית הבינה המלאכותית שתומכת בתמונות (כמו ChatGPT או Gemini) ולחצו על סמל המצלמה/הצרופה כדי להעלות את התמונה.","כתבו: 'תרגם לי את התפריט הזה לעברית, ותסביר אם יש מנות לא מוכרות'.","תקבלו תרגום מסודר של כל הפריטים – שימושי גם לבדיקת אלרגנים או מצרכים לא רצויים.","💡 טיפ: Google Translate (אפליקציה נפרדת וחינמית) גם מצלמת ומתרגמת טקסט בזמן אמת – מצוין כגיבוי."]},

// ── בנקאות ותשלומים דיגיטליים ──────────────────────────────────
{id:"bank-1",category:"banking",title:"מה זה Bit ו-Paybox, ואיך מעבירים כסף?",steps:["Bit ו-Paybox הן אפליקציות חינמיות להעברת כספים מהירה בין אנשים פרטיים (למשל לנכדים, או החזר כסף לחבר), בלי צורך בפרטי חשבון בנק.","התקינו את האפליקציה (Bit מבית בנק הפועלים, Paybox מבית בנק לאומי) מחנות האפליקציות — שתיהן מקושרות לכרטיס האשראי או לחשבון הבנק שלכם.","להעברת כסף: פתחו את האפליקציה > לחצו על 'שלח כסף' > בחרו את האדם מרשימת אנשי הקשר (חייב להיות גם לו את האפליקציה) > הקלידו סכום > אשרו.","לקבלת כסף: כשמישהו שולח לכם כסף, תקבלו הודעה — לחצו עליה ואשרו קבלה, הכסף יועבר לחשבון הבנק שלכם.","⚠️ זהירות: שלחו כסף רק לאנשים שאתם מכירים ובוטחים בהם. אם מישהו לא מוכר מבקש מכם 'לבדוק' שהאפליקציה עובדת על ידי שליחת כסף — זו תרמית, אל תשלחו!"]},
{id:"bank-2",category:"banking",title:"איך נכנסים לאפליקציית הבנק ובודקים יתרה?",steps:["הורידו את אפליקציית הבנק הרשמי שלכם מחנות האפליקציות (חפשו את שם הבנק המדויק: בנק הפועלים, בנק לאומי, מזרחי טפחות, דיסקונט וכו').","בפעם הראשונה: התחברות נעשית בדרך כלל עם מספר תעודת זהות וקוד סודי שקיבלתם בסניף, או עם הקוד שמשתמשים בו באתר האינטרנט של הבנק.","הגדירו זיהוי ביומטרי (טביעת אצבע או פנים) כדי שלא תצטרכו להקליד סיסמה בכל פעם.","במסך הראשי תוצג יתרת העו\"ש שלכם, ולשונית 'תנועות' או 'פירוט חשבון' תציג את כל ההוצאות וההכנסות האחרונות.","💡 טיפ: בדקו את היתרה באפליקציה לפני קנייה גדולה, ולא רק על סמך זיכרון."]},
{id:"bank-3",category:"banking",title:"איך משלמים חשבונות (חשמל, ארנונה) דרך האפליקציה?",steps:["באפליקציית הבנק, חפשו את האפשרות 'תשלום חשבונות' או 'תשלומים' (לרוב מסומנת בסמל של חשבונית או שובר).","סוג ראשון - תשלום עם 'קוד אסימון' (ברקוד): אם קיבלתם חשבון עם ברקוד מודפס, לחצו על 'סרוק חשבון' וכוונו את המצלמה לברקוד.","סוג שני - הוראת קבע: לתשלום אוטומטי וקבוע (כמו ארנונה חודשית) חפשו 'הוראות קבע' בתפריט הבנק והגדירו פעם אחת, התשלום יקרה אוטומטית בכל חודש.","אשרו את הסכום והתאריך, ולחצו 'בצע תשלום'.","שמרו תמיד את אישור התשלום (צילום מסך) למקרה שתצטרכו להוכיח ששילמתם."]},
{id:"bank-4",category:"banking",title:"זהירות מהונאות בנקאיות בטלפון וב-SMS",steps:["הבנק שלכם לעולם לא יתקשר או ישלח SMS ויבקש מכם לומר קוד אימות, סיסמה, או פרטי כרטיס אשראי מלאים!","אם מתקשרים ואומרים 'אנחנו מהבנק, יש בעיה בחשבון, תני לי את הקוד שקיבלת ב-SMS' — זו תמיד הונאה. נתקו את השיחה מיד.","הונאה נפוצה נוספת: SMS שמתחזה לבנק עם קישור 'לחצי כאן לאימות חשבון' — אל תלחצו! היכנסו לאפליקציה הרשמית של הבנק ישירות, לא דרך קישורים שמתקבלים בהודעה.","אם אתם בספק אם השיחה אמיתית: נתקו, וחייגו בעצמכם למספר הרשמי של הבנק (המודפס על הכרטיס שלכם או באתר הרשמי) כדי לבדוק.","אם חששתם שמסרתם פרט רגיש בטעות: התקשרו לבנק באופן מיידי כדי לחסום את הכרטיס/החשבון."]},
{id:"bank-5",category:"banking",title:"איך מצלמים ומפקידים צ'ק דרך הטלפון?",steps:["קיבלתם צ'ק ולא רוצים לנסוע לסניף? אפשר להפקיד אותו ישירות מהטלפון.","פתחו את אפליקציית הבנק > חפשו 'הפקדת שיק' או 'סריקת שיק' (סמל של צ'ק או מצלמה).","חתמו על גב הצ'ק (אישור הפקדה) לפני הצילום, בדומה לחתימה בסניף.","צלמו את הצד הקדמי של הצ'ק לפי ההנחיות שעל המסך, ולאחר מכן את הצד האחורי עם החתימה.","הזינו את הסכום הרשום בצ'ק כפי שמופיע, ואשרו את ההפקדה.","שמרו את הצ'ק הפיזי כ-14 יום לאחר ההפקדה, ליתר ביטחון, ולא תזרקו אותו מיד."]},

// ── בריאות דיגיטלית ────────────────────────────────────────────
{id:"health-1",category:"health",title:"איך נכנסים לאפליקציית קופת החולים?",steps:["חפשו בחנות האפליקציות את שם קופת החולים שלכם: כללית, מכבי, מאוחדת, או לאומית.","בכניסה הראשונה: תתבקשו להזין מספר תעודת זהות ולעבור אימות (לרוב קוד ב-SMS למספר הטלפון הרשום בקופה).","אם אינכם זוכרים את הפרטים הרשומים: התקשרו למספר שירות הלקוחות של הקופה (מופיע באתר שלהם) לקבלת עזרה באימות.","במסך הראשי תמצאו: קביעת תורים, מרשמים, תוצאות בדיקות, והודעות מהקופה.","הגדירו זיהוי ביומטרי (טביעת אצבע/פנים) כדי להיכנס בקלות בפעמים הבאות בלי להקליד סיסמה."]},
{id:"health-2",category:"health",title:"איך קובעים תור לרופא דרך האפליקציה?",steps:["פתחו את אפליקציית קופת החולים ולחצו על 'קביעת תורים' או 'תורים' (לרוב סמל של לוח שנה).","בחרו את סוג הרופא או המרפאה (רופא משפחה, מומחה, אחות וכו').","תוצג לכם רשימת תאריכים ושעות פנויים — לחצו על השעה המתאימה לכם.","אשרו את התור — תקבלו הודעת אישור עם פרטי הזמן והמיקום.","לביטול תור: היכנסו ל'התורים שלי' ולחצו על 'בטל' ליד התור הרצוי, מוקדם ככל האפשר כדי לפנות את התור למישהו אחר."]},
{id:"health-3",category:"health",title:"איך מקבלים מרשם דיגיטלי ובודקים תוצאות בדיקות?",steps:["מרשם דיגיטלי: כשהרופא רושם לכם תרופה, היא מופיעה אוטומטית באפליקציה תחת 'מרשמים שלי' או 'תרופות'.","אין צורך בנייר! בבית המרקחת מספיק להגיד את השם שלכם ומספר תעודת זהות, או להראות את המרשם הדיגיטלי על המסך.","תוצאות בדיקות: היכנסו ל'תוצאות בדיקות' או 'מעבדה' באפליקציה — בדיקות חדשות יסומנו בנקודה אדומה.","לחצו על בדיקה לפתיחת התוצאה המלאה. אם משהו לא מובן, אל תהססו לשאול את הרופא בפעם הבאה.","💡 טיפ: אפשר גם להוריד את תוצאות הבדיקה כקובץ PDF ולשלוח אותה לרופא אחר במייל או בוואטסאפ."]},
{id:"health-4",category:"health",title:"איך מתקשרים לרופא בשיחת וידאו (טלרפואה)?",steps:["טלרפואה מאפשרת להתייעץ עם רופא או אחות בשיחת וידאו מהבית, בלי לנסוע למרפאה.","פתחו את אפליקציית הקופה > חפשו 'טלרפואה' או 'מרפאה וירטואלית'.","בחרו את סוג הפנייה (רופא משפחה, התייעצות דחופה וכו') והצטרפו לתור הוירטואלי, או קבעו שעה מסוימת.","ודאו שיש לכם חיבור אינטרנט טוב (Wi-Fi מומלץ), ושהמצלמה והמיקרופון של הטלפון מאושרים לשימוש.","בזמן השיחה: דברו בבירור, והכינו מראש רשימת תרופות או תסמינים שתרצו להזכיר, כדי לא לשכוח."]},

// ── תמונות וגיבוי בעננה ────────────────────────────────────────
{id:"photo-1",category:"photos",title:"איך מוצאים תמונות ישנות וממיינים לפי תאריך?",steps:["פתחו את אפליקציית הגלריה (אנדרואיד) או Photos (אייפון).","התמונות מסודרות אוטומטית לפי תאריך הצילום, מהחדשה לישנה ביותר — גללו מטה כדי לחזור אחורה בזמן.","לחיפוש תמונה ספציפית: לחצו על סמל החיפוש (זכוכית מגדלת) והקלידו תיאור (למשל 'חתונה', 'ים', או שם של בן משפחה אם המכשיר תומך בזיהוי פנים).","ניתן גם לסנן לפי 'אלבומים' — הטלפון מקבץ אוטומטית תמונות של סלפי, מסכים, או אנשים מסוימים."]},
{id:"photo-2",category:"photos",title:"איך משחזרים תמונה שנמחקה בטעות?",steps:["מחקתם תמונה בטעות? אל תיבהלו — היא לא נמחקת לצמיתות מיד!","פתחו את אפליקציית הגלריה או Photos > לחצו על התפריט (☰ או 'ספרייה') > חפשו תיקייה בשם 'לאחרונה נמחק' (Recently Deleted) או 'אשפה' (Trash).","התמונות נשמרות שם בדרך כלל 30-60 יום לפני מחיקה סופית.","לחצו על התמונה הרצויה > בחרו 'שחזר' (Restore) — היא תחזור לגלריה הראשית במקומה המקורי."]},
{id:"photo-3",category:"photos",title:"איך משתפים אלבום שלם עם המשפחה?",steps:["רוצים לשתף את כל תמונות הטיול או החתונה עם המשפחה בלי לשלוח אחת-אחת בוואטסאפ?","ב-Google Photos: פתחו את האפליקציה > בחרו את כל התמונות הרצויות (לחיצה ארוכה על הראשונה, ואז גם על האחרות) > לחצו על סמל השיתוף.","בחרו 'צור קישור לשיתוף' (Create Link) — תקבלו קישור אחד שאפשר לשלוח בוואטסאפ, וכל מי שילחץ עליו יראה את כל האלבום.","ב-iCloud (אייפון): פתחו Photos > בחרו תמונות > לחצו שיתוף > 'אלבום משותף בעננה iCloud' > הזמינו אנשים לפי כתובת מייל.","💡 טיפ: קישור שיתוף נוח במיוחד לאירועים משפחתיים – כל אחד יכול גם להוסיף תמונות שלו לאותו אלבום."]},
{id:"photo-4",category:"photos",title:"איך מפנים מקום בטלפון בלי למחוק תמונות (גיבוי לעננה)?",steps:["אם הטלפון מתמלא בגלל תמונות, אפשר לגבות אותן ל'עננה' (אחסון אינטרנטי בטוח) ואז למחוק את הקבצים מהזיכרון הפיזי של הטלפון, בלי לאבד אותן.","ב-Google Photos (אנדרואיד): לחצו על תמונת הפרופיל בפינה > 'הגדרות גיבוי' > ודאו שהגיבוי האוטומטי מופעל.","לאחר שהגיבוי הסתיים (תוכלו לראות סימן ✓ על כל תמונה מגובה): לחצו על תמונת הפרופיל > 'פנה מקום במכשיר' — הטלפון ימחק את הקבצים המקוריים אך ישמור גישה מלאה לתמונות דרך האינטרנט.","באייפון: הגדרות > השם שלכם > iCloud > תמונות > הפעילו 'iCloud Photos' — התמונות יגובו אוטומטית ויוכלו 'לעבור לעננה' כשנדרש מקום.","⚠️ שימו לב: צפייה בתמונות מגובות (שלא נשמרות פיזית בטלפון) דורשת חיבור אינטרנט פעיל."]}
];
